import { PivotSheet } from 'https://cdn.jsdelivr.net/npm/@antv/s2@2/+esm';
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/@antv/s2@2.7.2/dist/s2.min.css'; shadowRoot.appendChild(css);
const el = document.createElement('div'); el.style.height = '400px'; shadowRoot.appendChild(el);
const sheet = new PivotSheet(el, data, { width: el.clientWidth, height: 400, tooltip: { getContainer: () => el } });
sheet.render();

